package dbgen

import "testing"

// TestPackage is a no-op placeholder so the coverage tool has something
// to instrument. This package is fully generated by sqlc (see
// `sqlc.yaml`) and has no branching logic worth unit-testing; without
// at least one test file, `go test -cover ./...` emits `no such tool
// "covdata"` noise that clutters CI output. sqlc regen does not touch
// `package_test.go`, only `*.sql.go`, so this file survives.
func TestPackage(t *testing.T) { t.Log("ok") }
